import{_ as a,o as l,c as s,ak as e}from"./chunks/framework.BsiU-GuW.js";const g=JSON.parse('{"title":"5.5 前沿导读（选学）：大模型(SAM)与生成式AI","description":"从“分割即服务”到生成式先验：医学影像中的 Foundation Model 时代","frontmatter":{"title":"5.5 前沿导读（选学）：大模型(SAM)与生成式AI","description":"从“分割即服务”到生成式先验：医学影像中的 Foundation Model 时代"},"headers":[],"relativePath":"guide/ch05/05-new-tech.md","filePath":"zh/guide/ch05/05-new-tech.md"}'),r={name:"guide/ch05/05-new-tech.md"};function n(t,i,h,o,p,d){return l(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="_5-5-前沿导读-选学-大模型-sam-与生成式ai" tabindex="-1">5.5 前沿导读（选学）：大模型(SAM)与生成式AI <a class="header-anchor" href="#_5-5-前沿导读-选学-大模型-sam-与生成式ai" aria-label="Permalink to “5.5 前沿导读（选学）：大模型(SAM)与生成式AI”">​</a></h1><blockquote><p>本页是 <strong>前沿导读 / 选学内容</strong>，建议在学完 5.1–5.4 四条主线后再阅读。</p></blockquote><h2 id="开场问题" tabindex="-1">开场问题 <a class="header-anchor" href="#开场问题" aria-label="Permalink to “开场问题”">​</a></h2><p>这一节回答的是：<strong>当我们已经理解预处理、分割、分类、增强这些基本工作流后，为什么还要再看 SAM 和生成式 AI，它们到底改变了什么。</strong></p><p>很多读者会在接触新技术时有两个常见困惑：</p><ul><li>已经有 U-Net、分类器、增强流程了，为什么还要单独讲基础模型和生成式模型？</li><li>这些新方法到底是在“替代前文”，还是只是给前文增加新的工具？</li></ul><p>这正是本节放在第 5 章最后的原因：<strong>它不是另起一章推翻前文，而是站在前四节之上，重新看“数据怎么来、标注怎么做、模型怎么交互、图像怎么补全”。</strong></p><hr><h2 id="直觉解释" tabindex="-1">直觉解释 <a class="header-anchor" href="#直觉解释" aria-label="Permalink to “直觉解释”">​</a></h2><p>可以把前四节理解成一条经典流水线：</p><ul><li>第 5.1 节解决“输入怎么整理”；</li><li>第 5.2 节解决“怎样给出精细区域”；</li><li>第 5.3 节解决“怎样先筛查再粗定位”；</li><li>第 5.4 节解决“怎样应对小样本和图像退化”。</li></ul><p>而这一节讨论的新范式，关注的是另一层问题：</p><ul><li><strong>SAM 一类基础模型</strong>，在改变“分割和标注是怎样发生的”；</li><li><strong>生成式 AI</strong>，在改变“缺失信息、退化图像和稀缺数据怎样被补足”。</li></ul><p>所以它与前文的关系不是平行替代，而更像是：</p><ul><li>给分割加上新的交互入口；</li><li>给数据构建和增强增加新的手段；</li><li>给恢复和重建引入更强的先验。</li></ul><p>这也是为什么它最适合放在第 5 章最后：<strong>只有先理解传统工作流的边界，才能看清这些新方法到底解决了哪个旧痛点。</strong></p><hr><h2 id="核心方法" tabindex="-1">核心方法 <a class="header-anchor" href="#核心方法" aria-label="Permalink to “核心方法”">​</a></h2><p>这一节只抓住 4 个关键点。</p><h3 id="_1-把-sam-看成-提示驱动的分割-标注引擎" tabindex="-1">1. 把 SAM 看成“提示驱动的分割/标注引擎” <a class="header-anchor" href="#_1-把-sam-看成-提示驱动的分割-标注引擎" aria-label="Permalink to “1. 把 SAM 看成“提示驱动的分割/标注引擎””">​</a></h3><p>SAM 最有价值的地方，常常不是直接替代专用医学分割模型，而是：</p><ul><li>加速交互式标注；</li><li>先生成粗掩膜，再交给人工修正；</li><li>帮助下游专用模型更快拿到训练数据。</li></ul><h3 id="_2-把生成式模型看成-补信息-的工具" tabindex="-1">2. 把生成式模型看成“补信息”的工具 <a class="header-anchor" href="#_2-把生成式模型看成-补信息-的工具" aria-label="Permalink to “2. 把生成式模型看成“补信息”的工具”">​</a></h3><p>GAN、Diffusion 等生成式方法，常见用途不是生成一张“好看图片”，而是：</p><ul><li>去噪；</li><li>去伪影；</li><li>重建欠采样数据；</li><li>做谨慎的数据合成与域扩展。</li></ul><h3 id="_3-新范式依然要服从旧任务目标" tabindex="-1">3. 新范式依然要服从旧任务目标 <a class="header-anchor" href="#_3-新范式依然要服从旧任务目标" aria-label="Permalink to “3. 新范式依然要服从旧任务目标”">​</a></h3><p>无论是 SAM 还是生成式 AI，最后仍然要落回前面几节的任务上：</p><ul><li>是不是让分割更快、更稳；</li><li>是不是让分类/检测更可靠；</li><li>是不是让增强与恢复更可控。</li></ul><h3 id="_4-风险控制比-新-更重要" tabindex="-1">4. 风险控制比“新”更重要 <a class="header-anchor" href="#_4-风险控制比-新-更重要" aria-label="Permalink to “4. 风险控制比“新”更重要”">​</a></h3><p>医学场景最怕的不是模型不够新，而是：</p><ul><li>SAM 在低对比、小病灶、3D 体数据上失稳；</li><li>生成式模型出现幻觉，凭空造出结构或抹掉病灶；</li><li>使用者把“看起来像”误当成“临床可用”。</li></ul><hr><h2 id="典型案例" tabindex="-1">典型案例 <a class="header-anchor" href="#典型案例" aria-label="Permalink to “典型案例”">​</a></h2><h3 id="场景-1-用-sam-做交互式标注提效" tabindex="-1">场景 1：用 SAM 做交互式标注提效 <a class="header-anchor" href="#场景-1-用-sam-做交互式标注提效" aria-label="Permalink to “场景 1：用 SAM 做交互式标注提效”">​</a></h3><ul><li><strong>痛点</strong>：像素级标注成本高，医生逐层勾画太慢。</li><li><strong>做法</strong>：点、框或粗涂提示 → SAM 给出候选掩膜 → 人工修正。</li><li><strong>它与前文关系</strong>：本质上是在为第 5.2 节的分割任务更快地产生训练数据。</li></ul><h3 id="场景-2-用生成式方法做去噪与重建" tabindex="-1">场景 2：用生成式方法做去噪与重建 <a class="header-anchor" href="#场景-2-用生成式方法做去噪与重建" aria-label="Permalink to “场景 2：用生成式方法做去噪与重建”">​</a></h3><ul><li><strong>痛点</strong>：低剂量 CT、加速 MRI、欠采样重建中信息不完整。</li><li><strong>做法</strong>：用生成式先验帮助恢复结构细节，但必须配合严格质量控制。</li><li><strong>它与前文关系</strong>：这是对第 5.4 节“恢复”问题的强化版本。</li></ul><h3 id="场景-3-用新范式服务下游分类-分割" tabindex="-1">场景 3：用新范式服务下游分类/分割 <a class="header-anchor" href="#场景-3-用新范式服务下游分类-分割" aria-label="Permalink to “场景 3：用新范式服务下游分类/分割”">​</a></h3><ul><li><strong>痛点</strong>：标注稀缺、中心差异大、模型泛化差。</li><li><strong>做法</strong>：SAM 提升标注效率，生成式方法做谨慎的数据补充或域扩展。</li><li><strong>它与前文关系</strong>：最终仍然是为了让第 5.2、5.3 节中的下游任务更稳。</li></ul><hr><h2 id="实践提示" tabindex="-1">实践提示 <a class="header-anchor" href="#实践提示" aria-label="Permalink to “实践提示”">​</a></h2><p>正文只保留帮助理解的最小片段；这里重点是“怎么判断该不该用”。</p><h3 id="_1-提示驱动分割可以先抽象成这样" tabindex="-1">1. 提示驱动分割可以先抽象成这样 <a class="header-anchor" href="#_1-提示驱动分割可以先抽象成这样" aria-label="Permalink to “1. 提示驱动分割可以先抽象成这样”">​</a></h3><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> prompt_to_mask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(image, prompt, foundation_segmentor):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> foundation_segmentor(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">image</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">image, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">prompt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">prompt)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_2-生成式恢复要始终和原图比对" tabindex="-1">2. 生成式恢复要始终和原图比对 <a class="header-anchor" href="#_2-生成式恢复要始终和原图比对" aria-label="Permalink to “2. 生成式恢复要始终和原图比对”">​</a></h3><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> restore_image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(image, generative_restorer):</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    restored </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> generative_restorer(image)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> image, restored</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="_3-实际落地时优先问这-4-个问题" tabindex="-1">3. 实际落地时优先问这 4 个问题 <a class="header-anchor" href="#_3-实际落地时优先问这-4-个问题" aria-label="Permalink to “3. 实际落地时优先问这 4 个问题”">​</a></h3><ul><li>它是在替代人工标注，还是在替代最终诊断模型；</li><li>它是否真的解决了前文中的某个明确痛点；</li><li>它会不会引入新的幻觉、漏检或边界错误；</li><li>有没有独立验证、质控和失败模式分析。</li></ul><h3 id="_4-一个稳妥的使用顺序" tabindex="-1">4. 一个稳妥的使用顺序 <a class="header-anchor" href="#_4-一个稳妥的使用顺序" aria-label="Permalink to “4. 一个稳妥的使用顺序”">​</a></h3><ol><li>先用 SAM 提高标注效率；</li><li>再训练面向具体任务的专用模型；</li><li>把生成式能力优先放在去噪、重建、伪影抑制等辅助环节；</li><li>所有结果都回到下游任务指标与人工复核上评估。</li></ol><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>这一节学会了：<strong>SAM 与生成式 AI 不是要推翻前文，而是在前文的预处理、分割、分类、增强工作流之上，重写“数据怎么来、分割怎么交互、退化怎么补救”的部分环节。</strong></p><p>这一节之所以放在第 5 章最后，是因为只有先理解前四节的经典问题与方法，才能判断这些新范式到底是在补哪块短板，也才能更理性地使用它们。</p>`,54)])])}const c=a(r,[["render",n]]);export{g as __pageData,c as default};
